const input = $json.categoria || $json.query || '';
const query = input.toLowerCase();

const categorias = {
  ofertas: [
    'oferta',
    'ofertas',
    'promoção',
    'promoções',
    'promocao',
    'promocoes',
    'desconto',
    'descontos'
  ],
  Kits: [
    'kit',
    'kits',
    'combo',
    'combos',
    'churrasco'
  ]
};

let categoria = '';

for (const [nome, termos] of Object.entries(categorias)) {
  if (termos.some(t => query.includes(t))) {
    categoria = nome;
    break;
  }
}

// Se não encontrou no mapa, usa a categoria original
if (!categoria) {
  categoria = input.trim();
}

return [{ json: { query, categoria } }];

const categoria = $('Receber Categoria').first().json.categoria || '';

const lista = $input.all().map(item => item.json);

if (lista.length === 0) {
  return [{
    json: {
      resultado: `Nenhum produto encontrado na categoria "${categoria}".`,
      produtos: []
    }
  }];
}

const fmt = (v) =>
  Number(v || 0).toLocaleString('pt-BR', {
    style: 'currency',
    currency: 'BRL'
  });

const limparNome = (nome) => {
  if (categoria.toLowerCase() === 'ofertas') {
    return (nome || '')
      .replace(/\bOferta\b/gi, '')
      .trim();
  }
  return nome || '';
};

// ativo=eq.true já garante que só produtos disponíveis chegam aqui.
const linhas = lista.map((p) => {
  const nomeLimpo = limparNome(p.nome);
  return `- ${nomeLimpo}: ${fmt(p.preco_atual)}/${p.unidade || 'un'}`;
});

const nome = $('Receber Categoria').first().json.nome_cliente || '';

const gatilhos = [
  nome ? `${nome}, tem interesse em algum? E so me dizer a quantidade que separo para voce!` : `Tem interesse em algum? E so me dizer a quantidade que separo para voce!`,
  nome ? `${nome}, esses produtos estao saindo bastante hoje. Qual deles voce quer garantir?` : `Esses produtos estao saindo bastante hoje. Qual deles voce quer garantir?`,
  nome ? `${nome}, posso separar agora para voce. Qual voce quer e em que quantidade?` : `Posso separar agora para voce. Qual voce quer e em que quantidade?`,
  nome ? `${nome}, nossos clientes adoram esses produtos. Qual deles te interessa?` : `Nossos clientes adoram esses produtos. Qual deles te interessa?`,
  nome ? `${nome}, aproveita que estao disponiveis agora. Me diz qual e a quantidade!` : `Aproveita que estao disponiveis agora. Me diz qual e a quantidade!`,
  nome ? `${nome}, quem experimenta sempre volta. Qual desses voce quer reservar?` : `Quem experimenta sempre volta. Qual desses voce quer reservar?`,
  nome ? `${nome}, e so escolher um que ja separo para voce ainda hoje!` : `E so escolher um que ja separo para voce ainda hoje!`,
  nome ? `${nome}, esses sao os favoritos dos nossos clientes. Qual voce quer levar?` : `Esses sao os favoritos dos nossos clientes. Qual voce quer levar?`,
  nome ? `${nome}, posso deixar tudo pronto para voce. Qual desses te agrada mais?` : `Posso deixar tudo pronto para voce. Qual desses te agrada mais?`,
  nome ? `${nome}, nao perde essa oportunidade! Me diz qual voce quer e em que quantidade.` : `Nao perde essa oportunidade! Me diz qual voce quer e em que quantidade.`
];

const gatilho = gatilhos[Math.floor(Math.random() * gatilhos.length)];
const cta = `\n\n${gatilho}`;

return [{
  json: {
    resultado:
      `Produtos da categoria ${categoria}:\n` +
      linhas.join('\n') + cta,

    produtos: lista.map((p) => ({
      produto_id: p.id || '',
      nome: limparNome(p.nome),
      preco_unitario: Number(p.preco_atual || 0),
      unidade: p.unidade || 'un'
    }))
  }
}];
